/**
 * @summary Get top selling menu items
 */
export const getGetTopItemsUrl = (params?: GetTopItemsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/reports/top-items?${stringifiedParams}`
    : `/api/reports/top-items`;
};

export const getTopItems = async (
  params?: GetTopItemsParams,
  options?: RequestInit,
): Promise<TopItem[]> => {
  return customFetch<TopItem[]>(getGetTopItemsUrl(params), {
    ...options,
    method: "GET",
  });
};

